#!/usr/bin/env node
/**
 * Create / configure a Supabase project for Noodl via Management API.
 *
 * Requires:
 *   SUPABASE_ACCESS_TOKEN  — https://supabase.com/dashboard/account/tokens
 *                            (GitHub login on the dashboard, then mint a token)
 * Optional:
 *   SUPABASE_ORG_ID
 *   PROJECT_NAME=noodl
 *   DB_PASSWORD=...        — auto-generated if missing
 *   REGION=ap-southeast-1
 *
 * Writes .env.local with VITE_SUPABASE_URL + VITE_SUPABASE_ANON_KEY
 * and applies supabase/schema.sql via the SQL API when possible.
 */
import { readFileSync, writeFileSync, existsSync } from 'node:fs';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';
import { randomBytes } from 'node:crypto';

const __dirname = dirname(fileURLToPath(import.meta.url));
const root = resolve(__dirname, '..');
const token = process.env.SUPABASE_ACCESS_TOKEN || process.env.SUPABASE_TOKEN;
const api = 'https://api.supabase.com/v1';

if (!token) {
  console.error(`
Missing SUPABASE_ACCESS_TOKEN.

GitHub PAT cannot call Supabase Management API directly.
Do this once (uses your GitHub-linked Supabase account):

  1. Open https://supabase.com/dashboard and sign in with GitHub
  2. https://supabase.com/dashboard/account/tokens → Generate token
  3. export SUPABASE_ACCESS_TOKEN=sbp_...
  4. node scripts/bootstrap-supabase.mjs

Or paste the token:
  SUPABASE_ACCESS_TOKEN=sbp_xxx node scripts/bootstrap-supabase.mjs
`);
  process.exit(1);
}

async function apiFetch(path, opts = {}) {
  const res = await fetch(`${api}${path}`, {
    ...opts,
    headers: {
      Authorization: `Bearer ${token}`,
      'Content-Type': 'application/json',
      ...(opts.headers || {}),
    },
  });
  const text = await res.text();
  let body;
  try {
    body = text ? JSON.parse(text) : null;
  } catch {
    body = text;
  }
  if (!res.ok) {
    const msg = typeof body === 'object' ? JSON.stringify(body) : body;
    throw new Error(`${opts.method || 'GET'} ${path} → ${res.status}: ${msg}`);
  }
  return body;
}

function genPassword() {
  return randomBytes(18).toString('base64url') + 'Aa1!';
}

async function main() {
  const orgs = await apiFetch('/organizations');
  const orgList = Array.isArray(orgs) ? orgs : orgs?.organizations || [];
  if (!orgList.length) throw new Error('No organizations on this Supabase account.');

  const orgId = process.env.SUPABASE_ORG_ID || orgList[0].id;
  console.log('Org:', orgId, orgList[0].name || '');

  const projects = await apiFetch('/projects');
  const list = Array.isArray(projects) ? projects : [];
  const name = process.env.PROJECT_NAME || 'noodl';
  let project = list.find((p) => p.name === name || p.ref === name);

  if (!project) {
    const dbPass = process.env.DB_PASSWORD || genPassword();
    const region = process.env.REGION || 'ap-southeast-1';
    console.log('Creating project', name, 'in', region, '…');
    project = await apiFetch('/projects', {
      method: 'POST',
      body: JSON.stringify({
        name,
        organization_id: orgId,
        db_pass: dbPass,
        region,
        plan: 'free',
      }),
    });
    console.log('Created ref:', project.id || project.ref);
    console.log('DB password (save once):', dbPass);
    // wait until healthy
    const ref = project.id || project.ref;
    for (let i = 0; i < 60; i++) {
      await new Promise((r) => setTimeout(r, 5000));
      const p = await apiFetch(`/projects/${ref}`);
      const status = p.status || p.healthy;
      console.log('  status…', p.status || JSON.stringify(status));
      if (p.status === 'ACTIVE_HEALTHY' || p.status === 'ACTIVE_UNHEALTHY' || p.status === 'ACTIVE') {
        project = p;
        break;
      }
    }
  } else {
    console.log('Using existing project', project.name, project.id || project.ref);
  }

  const ref = project.id || project.ref;
  const keys = await apiFetch(`/projects/${ref}/api-keys`);
  const anon =
    (Array.isArray(keys) ? keys : []).find((k) => k.name === 'anon' || k.tags?.includes('anon'))
      ?.api_key ||
    (Array.isArray(keys) ? keys : []).find((k) => k.type === 'anon')?.api_key;
  const service =
    (Array.isArray(keys) ? keys : []).find((k) => k.name === 'service_role' || k.tags?.includes('service_role'))
      ?.api_key;

  const url = `https://${ref}.supabase.co`;
  if (!anon) throw new Error('Could not read anon key');

  const envPath = resolve(root, '.env.local');
  const envBody = `# Generated by scripts/bootstrap-supabase.mjs — do not commit
VITE_SUPABASE_URL=${url}
VITE_SUPABASE_ANON_KEY=${anon}
# server-only (scripts / edge) — never expose to Vite client
SUPABASE_SERVICE_ROLE_KEY=${service || ''}
SUPABASE_PROJECT_REF=${ref}
`;
  writeFileSync(envPath, envBody);
  console.log('Wrote', envPath);

  // Apply schema via postgres REST is not available; use management query if present
  const schemaPath = resolve(root, 'supabase/schema.sql');
  if (existsSync(schemaPath) && service) {
    const sql = readFileSync(schemaPath, 'utf8');
    // Supabase database query endpoint (beta-ish)
    try {
      const res = await fetch(`${url}/rest/v1/rpc/`, { method: 'GET' });
      // Prefer SQL over pg meta
      const q = await fetch(`https://api.supabase.com/v1/projects/${ref}/database/query`, {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ query: sql }),
      });
      const t = await q.text();
      if (!q.ok) {
        console.warn('Schema apply via API failed — run schema.sql in SQL Editor manually.');
        console.warn(t.slice(0, 400));
      } else {
        console.log('Schema applied via Management SQL API.');
      }
    } catch (e) {
      console.warn('Schema push skipped:', e.message);
      console.warn('Open SQL Editor and paste supabase/schema.sql');
    }
  } else {
    console.log('Apply schema manually: Dashboard → SQL → paste supabase/schema.sql');
  }

  console.log(`
Next (Auth providers):
  1. Dashboard → Authentication → Providers → enable GitHub
  2. GitHub OAuth App:
       Homepage:  ${url.replace('.supabase.co', '') || 'https://YOUR_APP'}
       Callback:  ${url}/auth/v1/callback
     (also add http://localhost:5173/** and your Vercel URL under Redirect URLs)
  3. Optional: enable Google the same way
  4. npm run dev

Project URL: ${url}
Dashboard:   https://supabase.com/dashboard/project/${ref}
`);
}

main().catch((e) => {
  console.error(e);
  process.exit(1);
});
